const {endpoints, startTime} = $json;
const results = [];
const baseUrl = 'https://n8n.csr-llc.tech/webhook/';

for (const ep of endpoints) {
  const t0 = Date.now();
  let status = 'UNKNOWN', statusCode = 0, responseSize = 0, error = null;
  const timeout = ep.timeout || 10000;
  try {
    const resp = await this.helpers.httpRequest({
      method: ep.method,
      url: baseUrl + ep.path,
      headers: {'Content-Type': 'application/json'},
      body: ep.method === 'POST' ? ep.body : undefined,
      returnFullResponse: true,
      timeout: timeout,
      ignoreHttpStatusErrors: true
    });
    statusCode = resp.statusCode;
    const body = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body || '');
    responseSize = body.length;
    if (statusCode >= 200 && statusCode < 300 && responseSize > 5) status = 'PASS';
    else if (statusCode >= 200 && statusCode < 300) status = 'EMPTY';
    else if (statusCode === 404) status = 'NOT_FOUND';
    else status = 'FAIL';
  } catch(e) {
    status = (e.message || '').includes('timeout') ? 'TIMEOUT' : 'ERROR';
    error = e.message;
  }
  results.push({endpoint: ep.name, path: ep.path, status, statusCode, responseSize, latencyMs: Date.now() - t0, error});
}

const passed = results.filter(r => r.status === 'PASS').length;
const failed = results.filter(r => ['FAIL','NOT_FOUND','ERROR'].includes(r.status)).length;
const timedOut = results.filter(r => r.status === 'TIMEOUT').length;
const total = results.length;
const passRate = total > 0 ? Math.round((passed / total) * 10000) / 100 : 0;

return [{json: {total_endpoints: total, passed, failed, timed_out: timedOut, pass_rate: passRate, results, duration_ms: Date.now() - startTime}}];

